const pages=[['入口','account-entry.html'],['报价规则','index.html'],['标准价格','standard-prices.html'],['特殊规则','special-rules.html'],['报价参数','parameters.html'],['报价模板','templates.html'],['前台提示','frontend-strategy.html']];
const switcher=document.createElement('div');switcher.className='prototype-switcher';const select=document.createElement('select');pages.forEach(([label,url])=>{const option=document.createElement('option');option.textContent=label;option.value=url;option.selected=location.pathname.endsWith(url);select.appendChild(option)});select.addEventListener('change',()=>location.href=select.value);switcher.append('原型页 · ',select);document.body.appendChild(switcher);
document.querySelectorAll('[data-open-drawer]').forEach(button=>button.addEventListener('click',()=>document.querySelector('.drawer')?.classList.add('open')));document.querySelectorAll('[data-close-drawer]').forEach(button=>button.addEventListener('click',()=>document.querySelector('.drawer')?.classList.remove('open')));
const tabs=document.querySelector('.tabs');if(tabs&&!tabs.querySelector('[href="parameters.html"]')){const parameterTab=document.createElement('a');parameterTab.href='parameters.html';parameterTab.textContent='报价参数';const templateTab=tabs.querySelector('[href="templates.html"]');tabs.insertBefore(parameterTab,templateTab)}
if(document.title.includes('报价模板')){const description=document.querySelector('.page-head p');if(description)description.textContent='管理客户最终收到的 Excel 与 Word 版式。'}
